import type { ActivatorConfig as ActivatorInitializationConfigs } from '../config/config';
/**
 * Represents an activator interface.
 * This is currently implemented on Events Flow Activator, which checks whether an Event should be generated or not.
 */
export interface Activator {
    /**
     * @returns {boolean} True if the Events should be generated, otherwise false.
     */
    isActive: () => boolean;
}
/**
 * Represents the activator config.
 */
export type ActivatorConfig = {
    /**
     * The configs for the activator initialization.
     */
    configs: ActivatorInitializationConfigs;
    /**
     * The name of the service.
     * This should be composed by Fury's scope and the service name.
     * Example: `beta.events-flow-discovery`.
     */
    service: string;
    /**
     * The interval ID for the activator.
     * This is used to clear the interval when the activator is stopped.
     * @type {NodeJS.Timeout}
     */
    intervalID?: NodeJS.Timeout;
};
